package com.example.tokenauth.service;

import com.example.tokenauth.domain.Token;
import com.example.tokenauth.domain.User;
import com.example.tokenauth.repository.TokenRepository;
import com.example.tokenauth.repository.UserRepository;
import jakarta.servlet.http.Cookie;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Propagation;
import org.springframework.transaction.annotation.Transactional;
import java.time.Instant;
import java.time.temporal.ChronoUnit;
import java.util.HashMap;
import java.util.Map;
import java.util.Optional;
import java.util.UUID;
import java.util.concurrent.atomic.AtomicBoolean;

@Service
public class TokenService {

    private final TokenRepository tokenRepository;
    private final UserRepository userRepository;
    private final BCryptPasswordEncoder passwordEncoder;

    private static final String REFRESH_TOKEN_COOKIE_NAME = "refreshToken";
    private static final String ACCESS_TOKEN_TYPE = "ACCESS";
    private static final String REFRESH_TOKEN_TYPE = "REFRESH";
    private static final String ONE_TIME_TOKEN_TYPE = "ONE_TIME";

    @Autowired
    public TokenService(TokenRepository tokenRepository, UserRepository userRepository, BCryptPasswordEncoder passwordEncoder) {
        this.tokenRepository = tokenRepository;
        this.userRepository = userRepository;
        this.passwordEncoder = passwordEncoder;
    }

    // Token Generation Helper
    private String generateToken(String userId, String tokenType) {
        return UUID.randomUUID().toString() + "-" + tokenType + "-" + userId;
    }

    // Token Validation Helper with atomic check and consume
    private boolean validateAndConsumeOneTimeToken(String tokenValue, String userId) {
        Token token = tokenRepository.findByTokenValue(tokenValue)
                .filter(t -> t.getUserId().equals(userId) && !t.isConsumed() && !t.isExpired());

        if (token.isPresent()) {
            token.get().setConsumed(true);
            tokenRepository.save(token.get());
            return true;
        }
        return false;
    }

    // Find and mark token as revoked
    private Token findAndRevocate(String tokenValue) {
        Token token = tokenRepository.findByTokenValue(tokenValue)
                .filter(t -> !t.isRevoked() && !t.isConsumed());
        if (token.isPresent()) {
            token.get().setRevoked(true);
            tokenRepository.save(token.get());
        }
        return token;
    }

    // Find valid token for user
    private Token findValidTokenByUserId(String userId) {
        return tokenRepository.findByUserId(userId)
                .filter(t -> !t.isRevoked() && !t.isConsumed() && t.isValid());
    }

    // Find refresh token for user
    private Token findRefreshTokenByUserId(String userId) {
        return tokenRepository.findByUserIdAndTokenType(userId, REFRESH_TOKEN_TYPE)
                .filter(t -> !t.isRevoked() && !t.isConsumed());
    }

    // Find one-time token for user
    private Token findOneTimeTokenByUserId(String userId) {
        return tokenRepository.findByUserIdAndTokenType(userId, ONE_TIME_TOKEN_TYPE)
                .filter(t -> !t.isRevoked() && !t.isConsumed() && !t.isExpired());
    }

    // Login and token issuance
    @Transactional(propagation = Propagation.REQUIRES_NEW)
    public Map<String, Object> login(String username, String password) {
        User user = userRepository.findByUsername(username)
                .filter(u -> !u.isDeleted())
                .orElse(null);

        if (user == null) {
            user = new User();
            user.setUsername(username);
            user.setPassword(passwordEncoder.encode(password));
            userRepository.save(user);
        } else if (!passwordEncoder.matches(password, user.getPassword())) {
            throw new RuntimeException("Invalid credentials");
        }

        // Generate all three tokens atomically
        String userId = String.valueOf(user.getId());
        String accessToken = generateToken(userId, ACCESS_TOKEN_TYPE);
        String refreshToken = generateToken(userId, REFRESH_TOKEN_TYPE);
        String oneTimeToken = generateToken(userId, ONE_TIME_TOKEN_TYPE);

        Instant now = Instant.now();

        Token accessTokenEntity = new Token();
        accessTokenEntity.setTokenValue(accessToken);
        accessTokenEntity.setUserId(userId);
        accessTokenEntity.setTokenType(ACCESS_TOKEN_TYPE);
        accessTokenEntity.setIssuedAt(now);
        accessTokenEntity.setExpiresAt(now.plus(10, ChronoUnit.MINUTES));
        tokenRepository.save(accessTokenEntity);

        Token refreshTokenEntity = new Token();
        refreshTokenEntity.setTokenValue(refreshToken);
        refreshTokenEntity.setUserId(userId);
        refreshTokenEntity.setTokenType(REFRESH_TOKEN_TYPE);
        refreshTokenEntity.setIssuedAt(now);
        refreshTokenEntity.setExpiresAt(now.plus(24, ChronoUnit.HOURS));
        tokenRepository.save(refreshTokenEntity);

        Token oneTimeTokenEntity = new Token();
        oneTimeTokenEntity.setTokenValue(oneTimeToken);
        oneTimeTokenEntity.setUserId(userId);
        oneTimeTokenEntity.setTokenType(ONE_TIME_TOKEN_TYPE);
        oneTimeTokenEntity.setIssuedAt(now);
        oneTimeTokenEntity.setExpiresAt(now.plus(5, ChronoUnit.MINUTES));
        tokenRepository.save(oneTimeTokenEntity);

        Map<String, Object> response = new HashMap<>();
        response.put("accessToken", accessToken);
        response.put("oneTimeToken", oneTimeToken);
        return response;
    }

    // Renew Access Token using Refresh Token
    @Transactional(propagation = Propagation.REQUIRES_NEW)
    public String renewAccessToken(HttpServletRequest request, HttpServletResponse response) {
        String refreshTokenFromCookie = extractCookie(request, REFRESH_TOKEN_COOKIE_NAME);
        String refreshTokenFromHeader = request.getHeader("refreshToken");
        String refreshToken = refreshTokenFromCookie != null ? refreshTokenFromCookie : refreshTokenFromHeader;

        if (refreshToken == null || refreshToken.isEmpty()) {
            throw new RuntimeException("Refresh token is missing");
        }

        // Find and revoke old refresh token atomically
        Token oldRefreshToken = findAndRevocate(refreshToken);
        if (oldRefreshToken == null || !oldRefreshToken.isValid()) {
            throw new RuntimeException("Invalid refresh token");
        }

        // Get the user from the refresh token
        String userId = oldRefreshToken.getUserId();
        User user = userRepository.findByUsername(userId).orElse(null);
        if (user == null) {
            throw new RuntimeException("User not found");
        }

        // Issue new tokens
        String newAccessToken = generateToken(userId, ACCESS_TOKEN_TYPE);
        String newRefreshToken = generateToken(userId, REFRESH_TOKEN_TYPE);

        // Save new access token
        Token newAccessTokenEntity = new Token();
        newAccessTokenEntity.setTokenValue(newAccessToken);
        newAccessTokenEntity.setUserId(userId);
        newAccessTokenEntity.setTokenType(ACCESS_TOKEN_TYPE);
        newAccessTokenEntity.setIssuedAt(Instant.now());
        newAccessTokenEntity.setExpiresAt(Instant.now().plus(10, ChronoUnit.MINUTES));
        tokenRepository.save(newAccessTokenEntity);

        // Save new refresh token (revoked until saved to avoid race conditions)
        Token newRefreshTokenEntity = new Token();
        newRefreshTokenEntity.setTokenValue(newRefreshToken);
        newRefreshTokenEntity.setUserId(userId);
        newRefreshTokenEntity.setTokenType(REFRESH_TOKEN_TYPE);
        newRefreshTokenEntity.setIssuedAt(Instant.now());
        newRefreshTokenEntity.setExpiresAt(Instant.now().plus(24, ChronoUnit.HOURS));
        tokenRepository.save(newRefreshTokenEntity);

        // Set the new refresh token in the cookie
        Cookie refreshCookie = new Cookie(REFRESH_TOKEN_COOKIE_NAME, newRefreshToken);
        refreshCookie.setHttpOnly(true);
        refreshCookie.setSecure(false); // For dev/testing
        refreshCookie.setPath("/");
        refreshCookie.setMaxAge(86400);
        response.addCookie(refreshCookie);

        return newAccessToken;
    }

    // Validate and consume One-Time Token
    @Transactional(propagation = Propagation.REQUIRES_NEW)
    public boolean validateOneTimeToken(String tokenValue, String userId) {
        return validateAndConsumeOneTimeToken(tokenValue, userId);
    }

    // Extract cookie value from request
    private String extractCookie(HttpServletRequest request, String cookieName) {
        Cookie[] cookies = request.getCookies();
        if (cookies != null) {
            for (Cookie cookie : cookies) {
                if (cookie.getName().equals(cookieName)) {
                    return cookie.getValue();
                }
            }
        }
        return null;
    }

    // Logout - invalidate all tokens for user
    @Transactional(propagation = Propagation.REQUIRES_NEW)
    public void logout(String userId) {
        tokenRepository.deleteByUserId(userId);
        userRepository.deleteByUsername(userId);
    }

    // Helper to check if a refresh token is valid
    public boolean isValidRefreshToken(String refreshToken) {
        Token token = findAndRevocate(refreshToken);
        return token != null && token.isValid();
    }
}
